import{_ as r,o as a,c as i,a0 as t}from"./chunks/framework.7S7UUFQz.js";const m=JSON.parse('{"title":"TerritoryKit Product Requirements","description":"","frontmatter":{},"headers":[],"relativePath":"prd.md","filePath":"prd.md"}'),o={name:"prd.md"};function l(s,e,n,d,c,u){return a(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="territorykit-product-requirements" tabindex="-1">TerritoryKit Product Requirements <a class="header-anchor" href="#territorykit-product-requirements" aria-label="Permalink to &quot;TerritoryKit Product Requirements&quot;">​</a></h1><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>TerritoryKit is an open source TypeScript SDK for hierarchical, irregular polygon territories. It should give developers an H3-like API while working with real administrative boundaries or custom-designed regions instead of mathematical hexagons.</p><h2 id="primary-users" tabindex="-1">Primary Users <a class="header-anchor" href="#primary-users" aria-label="Permalink to &quot;Primary Users&quot;">​</a></h2><ul><li>SDK users building strategy games, delivery zones, field operations, election maps, campus maps, and administrative boundary tools.</li><li>Backend developers serving large territory datasets through Node.js, NestJS, and PostGIS.</li><li>Frontend developers rendering territory layers in MapLibre first, then other map renderers later.</li></ul><h2 id="mvp-scope" tabindex="-1">MVP Scope <a class="header-anchor" href="#mvp-scope" aria-label="Permalink to &quot;MVP Scope&quot;">​</a></h2><ul><li>Load and validate GeoJSON Polygon and MultiPolygon datasets.</li><li>Resolve a coordinate to a zone ID.</li><li>Return zone boundary, center, bbox, parent, children, ancestors, descendants, and neighbors.</li><li>Select active detail level from zoom.</li><li>Query zones by viewport bounds.</li><li>Provide a first MapLibre adapter package boundary.</li><li>Provide a NestJS integration package boundary.</li><li>Provide generator and CLI package boundaries.</li><li>Include small Turkey, Istanbul, and Fatih example datasets.</li></ul><h2 id="out-of-scope-for-mvp" tabindex="-1">Out Of Scope For MVP <a class="header-anchor" href="#out-of-scope-for-mvp" aria-label="Permalink to &quot;Out Of Scope For MVP&quot;">​</a></h2><ul><li>Full global administrative dataset distribution.</li><li>Satellite imagery or tile server operation.</li><li>Custom projection engine.</li><li>H3-grade global geodesic math.</li><li>Full visual territory editor.</li><li>Game ownership, scoring, or conquest rules inside <code>@territory-kit/core</code>.</li></ul><h2 id="success-criteria" tabindex="-1">Success Criteria <a class="header-anchor" href="#success-criteria" aria-label="Permalink to &quot;Success Criteria&quot;">​</a></h2><ul><li>Public API stays simple and H3-like.</li><li>Core package remains independent from renderers, backend frameworks, and game state.</li><li>Dataset schema is versioned and validates hierarchy and geometry quality.</li><li>Spatial lookup avoids brute-force production scans.</li><li>Examples prove Node.js, browser, MapLibre, and NestJS integration paths.</li><li>Checklist, roadmap, docs, and release notes stay consistent.</li></ul><h2 id="non-functional-requirements" tabindex="-1">Non-Functional Requirements <a class="header-anchor" href="#non-functional-requirements" aria-label="Permalink to &quot;Non-Functional Requirements&quot;">​</a></h2><ul><li>Runtime: Node.js <code>&gt;=22</code>; CI covers Node 22 and 24.</li><li>Package manager: pnpm workspace with Turborepo.</li><li>Package output: ESM, CJS, and declarations.</li><li>License: Apache-2.0 unless changed by ADR.</li><li>Documentation: VitePress and API docs.</li><li>Verification: build, typecheck, lint, unit tests, integration tests where relevant, and benchmark gates for spatial work.</li></ul>',13)])])}const h=r(o,[["render",l]]);export{m as __pageData,h as default};
